package com.enterprise.state;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.crypto.CipherText;
import org.owasp.esapi.crypto.PlainText;
import org.owasp.esapi.errors.EncryptionException;

/** Wraps ESAPI's authenticated Encryptor to (de)serialize session state. */
public class SessionStateCodec {

    /** Encrypt-then-MAC via ESAPI; the serialized CipherText carries IV, ciphertext, and the MAC. */
    public byte[] encrypt(byte[] state) throws EncryptionException {
        CipherText ct = ESAPI.encryptor().encrypt(new PlainText(state));
        return ct.asPortableSerializedByteArray();
    }

    /** ESAPI validates the MAC before it decrypts; an invalid MAC throws EncryptionException. */
    public byte[] decrypt(byte[] serialized) throws EncryptionException {
        CipherText ct = CipherText.fromPortableSerializedBytes(serialized);
        return ESAPI.encryptor().decrypt(ct).asBytes();
    }
}
