package audit.integrity;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encryptor;
import org.owasp.esapi.crypto.CipherText;
import org.owasp.esapi.crypto.PlainText;

/** Builds integrity-protecting wrappers backed by ESAPI's authenticated Encryptor. */
public final class IntegrityWrapperFactory {

    public static final class Builder {
        private Encryptor encryptor = ESAPI.encryptor();
        public Builder encryptor(Encryptor e) { this.encryptor = e; return this; }
        public IntegrityWrapper build() { return new IntegrityWrapper(encryptor); }
    }

    public static final class IntegrityWrapper {
        private final Encryptor enc;
        IntegrityWrapper(Encryptor enc) { this.enc = enc; }
        public byte[] protect(byte[] record) throws Exception {
            return enc.encrypt(new PlainText(record)).asPortableSerializedByteArray();
        }
        public byte[] open(byte[] sealed) throws Exception {
            return enc.decrypt(CipherText.fromPortableSerializedBytes(sealed)).asBytes();
        }
    }
}
